 using Store;

 namespace ShoppingCart.Tests;

 [TestClass]
 public sealed class ShoppingCartTests
 {
     private Store.ShoppingCart _cart = null!;

     [TestInitialize]
     public void Setup()
     {
         _cart = new Store.ShoppingCart();
     }

     // ---------------------------------------------------------------
     //  AddItem
     // ---------------------------------------------------------------

     [TestMethod]
     public void AddItem_SingleItem_IncreasesTotal()
     {
         _cart.AddItem("SKU-001", quantity: 2, price: 9.99m);

         Assert.AreEqual(19.98m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void AddItem_MultipleDistinctItems_SumsCorrectly()
     {
         _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
         _cart.AddItem("SKU-002", quantity: 3, price: 5.00m);

         Assert.AreEqual(25.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void AddItem_SameSkuTwice_CombinesQuantity()
     {
         _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
         _cart.AddItem("SKU-001", quantity: 2, price: 10.00m);

         Assert.AreEqual(30.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void AddItem_ZeroQuantity_ThrowsArgumentException()
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _cart.AddItem("SKU-001", quantity: 0, price: 10.00m));
     }

     [TestMethod]
     public void AddItem_NegativeQuantity_ThrowsArgumentException()
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _cart.AddItem("SKU-001", quantity: -1, price: 10.00m));
     }

     [TestMethod]
     public void AddItem_NegativePrice_ThrowsArgumentException()
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _cart.AddItem("SKU-001", quantity: 1, price: -5.00m));
     }

     [TestMethod]
     [DataRow(null)]
     [DataRow("")]
     [DataRow("   ")]
     public void AddItem_InvalidSku_ThrowsArgumentException(string? sku)
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _cart.AddItem(sku!, quantity: 1, price: 10.00m));
     }

     // ---------------------------------------------------------------
     //  RemoveItem
     // ---------------------------------------------------------------

     [TestMethod]
     public void RemoveItem_ExistingItem_RemovesFromCart()
     {
         _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
         _cart.AddItem("SKU-002", quantity: 1, price: 20.00m);

         _cart.RemoveItem("SKU-001");

         Assert.AreEqual(20.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void RemoveItem_OnlyItem_CartBecomesEmpty()
     {
         _cart.AddItem("SKU-001", quantity: 3, price: 5.00m);

         _cart.RemoveItem("SKU-001");

         Assert.AreEqual(0m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void RemoveItem_NonExistentSku_ThrowsInvalidOperationException()
     {
         Assert.ThrowsExactly<InvalidOperationException>(
             () => _cart.RemoveItem("NO-SUCH-SKU"));
     }

     [TestMethod]
     [DataRow(null)]
     [DataRow("")]
     public void RemoveItem_InvalidSku_ThrowsArgumentException(string? sku)
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _cart.RemoveItem(sku!));
     }

     // ---------------------------------------------------------------
     //  CalculateTotal
     // ---------------------------------------------------------------

     [TestMethod]
     public void CalculateTotal_EmptyCart_ReturnsZero()
     {
         Assert.AreEqual(0m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void CalculateTotal_AfterAddAndRemove_ReturnsCorrectTotal()
     {
         _cart.AddItem("SKU-001", quantity: 2, price: 15.00m);
         _cart.AddItem("SKU-002", quantity: 1, price: 7.50m);
         _cart.RemoveItem("SKU-002");

         Assert.AreEqual(30.00m, _cart.CalculateTotal());
     }

     [TestMethod]
     public void CalculateTotal_LargeQuantity_HandlesCorrectly()
     {
         _cart.AddItem("SKU-001", quantity: 1000, price: 0.01m);

         Assert.AreEqual(10.00m, _cart.CalculateTotal());
     }

     // ---------------------------------------------------------------
     //  ApplyCoupon
     // ---------------------------------------------------------------

     [TestMethod]
     public void ApplyCoupon_ValidCode_ReducesTotal()
     {
         _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);

         _cart.ApplyCoupon("SAVE10");

         Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
             "Total should be reduced after applying a valid coupon.");
     }

     [TestMethod]
     public void ApplyCoupon_InvalidCode_ThrowsInvalidOperationException()
     {
         _cart.AddItem("SKU-001", quantity: 1, price: 50.00m);

         Assert.ThrowsExactly<InvalidOperationException>(
             () => _cart.ApplyCoupon("BOGUS"));
     }

     [TestMethod]
     [DataRow(null)]
     [DataRow("")]
     public void ApplyCoupon_NullOrEmptyCode_ThrowsArgumentException(string? code)
     {
         Assert.ThrowsExactly<ArgumentException>(
             () => _cart.ApplyCoupon(code!));
     }

     [TestMethod]
     public void ApplyCoupon_EmptyCart_ThrowsInvalidOperationException()
     {
         Assert.ThrowsExactly<InvalidOperationException>(
             () => _cart.ApplyCoupon("SAVE10"));
     }

     [TestMethod]
     public void ApplyCoupon_AppliedTwice_ThrowsInvalidOperationException()
     {
         _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);
         _cart.ApplyCoupon("SAVE10");

         Assert.ThrowsExactly<InvalidOperationException>(
             () => _cart.ApplyCoupon("SAVE10"));
     }

     // ---------------------------------------------------------------
     //  End-to-end scenario
     // ---------------------------------------------------------------

     [TestMethod]
     public void FullWorkflow_AddRemoveCoupon_ProducesExpectedTotal()
     {
         _cart.AddItem("WIDGET", quantity: 4, price: 25.00m);
         _cart.AddItem("GADGET", quantity: 1, price: 50.00m);
         _cart.RemoveItem("GADGET");
         _cart.ApplyCoupon("SAVE10");

         decimal total = _cart.CalculateTotal();

         Assert.IsTrue(total > 0m, "Total should be positive after discount.");
         Assert.IsTrue(total < 100.00m, "Total should be less than the pre-coupon amount.");
     }
 }

